/**
 * Fetch the community-maintained disposable email domains list from GitHub
 * and write it to app/lib/disposable-email-domains.generated.ts as a frozen
 * Set<string> exported for use by the email validation layer.
 *
 * Source: https://github.com/disposable-email-domains/disposable-email-domains
 * License: Public domain (CC0)
 *
 * Behavior:
 * - On network failure, leaves the existing generated file in place (best-effort).
 *   The build does NOT fail closed — we always have a committed fallback list.
 * - Validates entries with a strict domain regex.
 * - Writes deterministic, sorted output for clean diffs.
 *
 * Usage:
 *   node scripts/fetch-disposable-domains.mjs
 */
import { writeFileSync, existsSync } from "fs";
import { resolve, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = resolve(__dirname, "..");
const outPath = resolve(root, "app/lib/disposable-email-domains.generated.ts");

const SOURCE_URL =
  "https://raw.githubusercontent.com/disposable-email-domains/disposable-email-domains/main/disposable_email_blocklist.conf";

const FETCH_TIMEOUT_MS = 15_000;
const DOMAIN_REGEX = /^(?=.{1,253}$)(?:[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?\.)+[a-z]{2,63}$/i;

function log(step, detail = {}) {
  console.log(`[fetch-disposable] ${step}`, JSON.stringify(detail));
}

async function fetchList() {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS);
  try {
    const res = await fetch(SOURCE_URL, {
      signal: controller.signal,
      headers: { "User-Agent": "eod-hub-disposable-domain-refresh/1.0" },
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return await res.text();
  } finally {
    clearTimeout(timer);
  }
}

function parseDomains(text) {
  const seen = new Set();
  for (const raw of text.split(/\r?\n/)) {
    const trimmed = raw.trim().toLowerCase();
    if (!trimmed || trimmed.startsWith("#")) continue;
    if (!DOMAIN_REGEX.test(trimmed)) continue;
    seen.add(trimmed);
  }
  return [...seen].sort();
}

function renderModule(domains) {
  const header = [
    "// AUTO-GENERATED by scripts/fetch-disposable-domains.mjs",
    `// Source: ${SOURCE_URL}`,
    "// Do NOT edit by hand. Run `npm run refresh:disposable` to regenerate.",
    "",
    `export const DISPOSABLE_DOMAINS_GENERATED: ReadonlySet<string> = Object.freeze(new Set<string>([`,
  ].join("\n");
  const body = domains.map((d) => `  ${JSON.stringify(d)},`).join("\n");
  const footer = "]));\n";
  return `${header}\n${body}\n${footer}`;
}

async function main() {
  log("start", { source: SOURCE_URL });

  let text;
  try {
    text = await fetchList();
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    if (existsSync(outPath)) {
      log("fetch_failed_using_existing", { error: msg });
      process.exit(0);
    }
    console.error(
      `[fetch-disposable] FATAL: network fetch failed and no committed fallback exists at ${outPath}. ` +
        `Error: ${msg}`,
    );
    process.exit(1);
  }

  const domains = parseDomains(text);
  if (domains.length < 100) {
    log("suspiciously_small_list", { count: domains.length });
    if (existsSync(outPath)) {
      log("keeping_existing_fallback");
      process.exit(0);
    }
    console.error("[fetch-disposable] FATAL: list too small and no fallback exists");
    process.exit(1);
  }

  const out = renderModule(domains);
  writeFileSync(outPath, out, "utf8");
  log("wrote", { path: outPath, count: domains.length });
}

main().catch((err) => {
  console.error("[fetch-disposable] unexpected error:", err);
  process.exit(1);
});
